    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
}

/**
 * Fetch wrapper with automatic res.ok check.
 * Extracts FastAPI error detail when available.
 */
async function safeFetch(url, options) {
    const res = await fetch(url, options);
    if (!res.ok) {
        let detail = res.statusText;
        try {
            const err = await res.json();
            detail = err.detail || err.error || detail;
        } catch { /* response wasn't JSON */ }
        throw new Error(`HTTP ${res.status}: ${detail}`);
    }
    return res;
}

/**
 * Poll a task until it completes (fallback when WebSocket is not available).
 */
async function pollTask(taskId, onUpdate, intervalMs = 2000, maxAttempts = 300) {
    for (let i = 0; i < maxAttempts; i++) {
        try {
            const res = await safeFetch(`/api/task/${taskId}`);
            const data = await res.json();
            if (onUpdate) onUpdate(data);

            if (data.status === 'completed' || data.status === 'failed' || data.status === 'cancelled') {
                return data;
            }
        } catch (e) {
            console.error('Poll error:', e);
        }
        await new Promise(r => setTimeout(r, intervalMs));
    }
    return null;
}

